# Bridge1x2RdTB - Testbench for bridge_1x2_rd
# Generated by bridge test generator from CSV configuration

import os
import sys

# Import framework utilities (PYTHONPATH includes bin/)
from TBClasses.shared.utilities import get_repo_root

# Add repo root to Python path using robust git-based method
repo_root = get_repo_root()
sys.path.insert(0, repo_root)

import cocotb
from cocotb.triggers import RisingEdge, ClockCycles
from TBClasses.shared.tbbase import TBBase
from CocoTBFramework.components.gaxi.gaxi_master import GAXIMaster
from CocoTBFramework.components.gaxi.gaxi_slave import GAXISlave
from CocoTBFramework.components.axi4.axi4_field_configs import AXI4FieldConfigHelper
from CocoTBFramework.components.apb.apb_components import APBMaster, APBSlave


class Bridge1x2RdTB(TBBase):
    """
    Testbench for bridge_1x2_rd bridge

    Configuration:
        Masters: 1 (cpu_rd)
        Slaves:  2 (ddr_rd, sram_rd)
        Channels: RD
        Data Width: 32
        Addr Width: 64
        ID Width: 8
    """

    def __init__(self, dut):
        super().__init__(dut)
        self.dut = dut
        self.clock = dut.aclk
        self.clock_name = 'aclk'
        self.reset_n = dut.aresetn

        # Bridge configuration
        self.num_masters = 1
        self.num_slaves = 2
        self.data_width = 32
        self.addr_width = 64
        self.id_width = 8

        # Slave protocol types (for protocol-specific response handling)
        self.slave_protocols = {
            0: 'axi4',  # ddr_rd
            1: 'axi4',  # sram_rd
        }

        # GAXI components for each master (slave interfaces on bridge)
        self._setup_master_0_cpu_rd()

        # GAXI components for each slave (master interfaces on bridge)
        self._setup_slave_0_ddr_rd()
        self._setup_slave_1_sram_rd()

    def _setup_master_0_cpu_rd(self):
        """Setup GAXI components for master 0: cpu_rd"""

        # AR channel (master 0 read address)
        self.ar_m0 = GAXIMaster(
            dut=self.dut,
            title="AR_M0",
            prefix="cpu_rd_axi_",
            clock=self.clock,
            field_config=AXI4FieldConfigHelper.create_ar_field_config(
                4, 32, 1
            ),
            pkt_prefix="ar",
            multi_sig=True,
            log=self.log
        )

        # R channel (master 0 read data)
        self.r_m0 = GAXISlave(
            dut=self.dut,
            title="R_M0",
            prefix="cpu_rd_axi_",
            clock=self.clock,
            field_config=AXI4FieldConfigHelper.create_r_field_config(
                4, 32, 1
            ),
            pkt_prefix="r",
            multi_sig=True,
            log=self.log
        )
    def _setup_slave_0_ddr_rd(self):
        """Setup components for slave 0: ddr_rd (protocol: axi4)"""        # AXI4 protocol slave - use GAXI BFMs
        # AR channel (slave 0 read address)
        self.ar_s0 = GAXISlave(
            dut=self.dut,
            title="AR_S0",
            prefix="ddr_rd_axi_",
            clock=self.clock,
            field_config=AXI4FieldConfigHelper.create_ar_field_config(
                4, 32, 1
            ),
            pkt_prefix="ar",
            multi_sig=True,
            log=self.log
        )

        # R channel (slave 0 read data)
        self.r_s0 = GAXIMaster(
            dut=self.dut,
            title="R_S0",
            prefix="ddr_rd_axi_",
            clock=self.clock,
            field_config=AXI4FieldConfigHelper.create_r_field_config(
                4, 32, 1
            ),
            pkt_prefix="r",
            multi_sig=True,
            log=self.log
        )
    def _setup_slave_1_sram_rd(self):
        """Setup components for slave 1: sram_rd (protocol: axi4)"""        # AXI4 protocol slave - use GAXI BFMs
        # AR channel (slave 1 read address)
        self.ar_s1 = GAXISlave(
            dut=self.dut,
            title="AR_S1",
            prefix="sram_rd_axi_",
            clock=self.clock,
            field_config=AXI4FieldConfigHelper.create_ar_field_config(
                4, 32, 1
            ),
            pkt_prefix="ar",
            multi_sig=True,
            log=self.log
        )

        # R channel (slave 1 read data)
        self.r_s1 = GAXIMaster(
            dut=self.dut,
            title="R_S1",
            prefix="sram_rd_axi_",
            clock=self.clock,
            field_config=AXI4FieldConfigHelper.create_r_field_config(
                4, 32, 1
            ),
            pkt_prefix="r",
            multi_sig=True,
            log=self.log
        )
    async def setup_clocks_and_reset(self):
        """Complete initialization - starts clocks and performs reset"""
        await self.start_clock(self.clock_name, freq=10, units='ns')

        # Reset sequence
        await self.assert_reset()
        await self.wait_clocks(self.clock_name, 10)
        await self.deassert_reset()
        await self.wait_clocks(self.clock_name, 5)

    async def assert_reset(self):
        """Assert reset signal (active-low for AXI4)"""
        self.reset_n.value = 0

    async def deassert_reset(self):
        """Deassert reset signal"""
        self.reset_n.value = 1

    async def write_transaction(self, master_idx, address, data, burst_len=1, txn_id=0):
        """
        Perform a write transaction from specified master

        Args:
            master_idx: Master index (0-0)
            address: Target address
            data: Data value or list of data values
            burst_len: Burst length (default: 1 for single beat)
            txn_id: Transaction ID (default: 0)
        """
        # Get master components
        aw_master = getattr(self, f'aw_m{master_idx}')
        w_master = getattr(self, f'w_m{master_idx}')

        # Send AW
        aw_pkt = aw_master.create_packet(
            addr=address,
            id=txn_id,
            len=burst_len - 1,
            size=0x2,
            burst=0x1  # INCR
        )
        await aw_master.send(aw_pkt)

        # Send W data
        if not isinstance(data, list):
            data = [data]

        for i, d in enumerate(data):
            w_pkt = w_master.create_packet(
                data=d,
                strb=(1 << (32 // 8)) - 1,
                last=1 if i == len(data) - 1 else 0
            )
            await w_master.send(w_pkt)

    async def read_transaction(self, master_idx, address, burst_len=1, txn_id=0):
        """
        Perform a read transaction from specified master

        Args:
            master_idx: Master index (0-0)
            address: Target address
            burst_len: Burst length (default: 1 for single beat)
            txn_id: Transaction ID (default: 0)
        """
        # Get master component
        ar_master = getattr(self, f'ar_m{master_idx}')

        # Send AR
        ar_pkt = ar_master.create_packet(
            addr=address,
            id=txn_id,
            len=burst_len - 1,
            size=0x2,
            burst=0x1  # INCR
        )
        await ar_master.send(ar_pkt)

    async def slave_respond_write(self, slave_idx, txn_id=0, resp=0):
        """
        Send write response from specified slave

        Args:
            slave_idx: Slave index (0-1)
            txn_id: Transaction ID to respond to
            resp: Response code (0=OKAY, 1=EXOKAY, 2=SLVERR, 3=DECERR)
        """
        # Check protocol type for this slave
        protocol = self.slave_protocols.get(slave_idx, 'axi4').lower()

        if protocol == 'apb':
            # APB slaves handle response automatically via APBSlave BFM
            # No manual B channel response needed
            pass
        else:
            # AXI4 slave - send B response
            b_master = getattr(self, f'b_s{slave_idx}')

            b_pkt = b_master.create_packet(
                id=txn_id,
                resp=resp
            )
            await b_master.send(b_pkt)

    async def slave_respond_read(self, slave_idx, data, txn_id=0, resp=0, last=True):
        """
        Send read response from specified slave

        Args:
            slave_idx: Slave index (0-1)
            data: Data value or list of data values
            txn_id: Transaction ID to respond to
            resp: Response code (0=OKAY, 1=EXOKAY, 2=SLVERR, 3=DECERR)
            last: Last beat in burst
        """
        # Check protocol type for this slave
        protocol = self.slave_protocols.get(slave_idx, 'axi4').lower()

        if protocol == 'apb':
            # APB slaves handle response automatically via APBSlave BFM
            # No manual R channel response needed
            pass
        else:
            # AXI4 slave - send R response
            r_master = getattr(self, f'r_s{slave_idx}')

            if not isinstance(data, list):
                data = [data]

            for i, d in enumerate(data):
                r_pkt = r_master.create_packet(
                    id=txn_id,
                    data=d,
                    resp=resp,
                    last=1 if (i == len(data) - 1 and last) else 0
                )
                await r_master.send(r_pkt)

    # ----------------------------------------------------------------------
    # Routing-correctness verification helpers
    # ----------------------------------------------------------------------
    # The connectivity test used to *call* slave_respond_write(slave_idx=N)
    # without first checking that the AW had actually arrived at slave N.
    # That meant a routing bug — bridge sends the AW to slave M instead — was
    # invisible: the test responded as N, the master saw a B, and everything
    # "looked fine". These helpers check the AXI4 slave BFM receive queues
    # so a misroute fails the test loudly.
    #
    # APB slaves are intentionally skipped — they're driven by the APBSlave
    # BFM which has its own transaction model, not a GAXISlave _recvQ.

    def _axi4_slave_indices(self):
        """Return slave indices whose protocol is AXI4 / AXIL (have GAXI slave BFMs)."""
        return [i for i, p in self.slave_protocols.items() if p.lower() != 'apb']

    async def _wait_for_queue(self, queue, max_cycles=100):
        """Tick the clock up to `max_cycles` waiting for `queue` to be non-empty.

        Returns the cycle count at which the queue first had content, or
        max_cycles if the deadline expired. The bridge has multi-stage
        skid buffers between master and slave ports, so a fixed 2-cycle
        wait is too tight on wider topologies. Polling lets us exit
        early on the common (fast) case and still give slow paths
        a generous bound before flagging a real misroute.
        """
        for cyc in range(max_cycles):
            if len(queue) > 0:
                return cyc
            await ClockCycles(self.clock, 1)
        return max_cycles

    async def expect_aw_at_slave(self, slave_idx, expected_addr, expected_id=0,
                                  max_settle_cycles=100):
        """
        Verify the bridge routed an AW to ``slave_idx`` and only there.

        Pops one AW from slave_idx's recvQ, compares addr+id, and confirms
        every other AXI4 slave's recvQ is still empty. Raises AssertionError
        on any mismatch — including silent misroutes that earlier versions
        of the connectivity test missed entirely.
        """
        protocol = self.slave_protocols.get(slave_idx, 'axi4').lower()
        if protocol == 'apb':
            return  # APB slaves don't expose a GAXI _recvQ

        target = getattr(self, f'aw_s{slave_idx}')
        await self._wait_for_queue(target._recvQ, max_settle_cycles)
        assert len(target._recvQ) >= 1, (
            f"AW to slave {slave_idx} (addr=0x{expected_addr:08x}) never arrived "
            f"after {max_settle_cycles} cycles — bridge dropped the transaction "
            f"or routed it elsewhere"
        )
        pkt = target._recvQ.popleft()
        assert int(pkt.addr) == expected_addr, (
            f"AW addr mismatch at slave {slave_idx}: "
            f"got 0x{int(pkt.addr):08x}, expected 0x{expected_addr:08x}"
        )
        assert int(pkt.id) == expected_id, (
            f"AW id mismatch at slave {slave_idx}: "
            f"got {int(pkt.id)}, expected {expected_id}"
        )

        for other in self._axi4_slave_indices():
            if other == slave_idx:
                continue
            other_q = getattr(self, f'aw_s{other}')._recvQ
            assert len(other_q) == 0, (
                f"AW for slave {slave_idx} (addr=0x{expected_addr:08x}) "
                f"leaked to slave {other} (queue depth={len(other_q)})"
            )

    async def expect_ar_at_slave(self, slave_idx, expected_addr, expected_id=0,
                                  max_settle_cycles=100):
        """Read-side analogue of expect_aw_at_slave."""
        protocol = self.slave_protocols.get(slave_idx, 'axi4').lower()
        if protocol == 'apb':
            return

        target = getattr(self, f'ar_s{slave_idx}')
        await self._wait_for_queue(target._recvQ, max_settle_cycles)
        assert len(target._recvQ) >= 1, (
            f"AR to slave {slave_idx} (addr=0x{expected_addr:08x}) never arrived "
            f"after {max_settle_cycles} cycles"
        )
        pkt = target._recvQ.popleft()
        assert int(pkt.addr) == expected_addr, (
            f"AR addr mismatch at slave {slave_idx}: "
            f"got 0x{int(pkt.addr):08x}, expected 0x{expected_addr:08x}"
        )
        assert int(pkt.id) == expected_id, (
            f"AR id mismatch at slave {slave_idx}: "
            f"got {int(pkt.id)}, expected {expected_id}"
        )

        for other in self._axi4_slave_indices():
            if other == slave_idx:
                continue
            other_q = getattr(self, f'ar_s{other}')._recvQ
            assert len(other_q) == 0, (
                f"AR for slave {slave_idx} leaked to slave {other} "
                f"(queue depth={len(other_q)})"
            )

    async def expect_b_at_master(self, master_idx, expected_id=0,
                                  expected_resp=0, max_settle_cycles=100):
        """Verify the B response routed back to the originating master."""
        target = getattr(self, f'b_m{master_idx}')
        await self._wait_for_queue(target._recvQ, max_settle_cycles)
        assert len(target._recvQ) >= 1, (
            f"B response never reached master {master_idx} (txn_id={expected_id}) "
            f"after {max_settle_cycles} cycles"
        )
        pkt = target._recvQ.popleft()
        assert int(pkt.id) == expected_id, (
            f"B id mismatch at master {master_idx}: "
            f"got {int(pkt.id)}, expected {expected_id}"
        )
        assert int(pkt.resp) == expected_resp, (
            f"B resp mismatch at master {master_idx}: "
            f"got {int(pkt.resp)}, expected {expected_resp}"
        )

    async def expect_r_at_master(self, master_idx, expected_id=0,
                                  expected_data=None, expected_resp=0,
                                  max_settle_cycles=100):
        """Verify the R response routed back to the originating master."""
        target = getattr(self, f'r_m{master_idx}')
        await self._wait_for_queue(target._recvQ, max_settle_cycles)
        assert len(target._recvQ) >= 1, (
            f"R response never reached master {master_idx} (txn_id={expected_id}) "
            f"after {max_settle_cycles} cycles"
        )
        pkt = target._recvQ.popleft()
        assert int(pkt.id) == expected_id, (
            f"R id mismatch at master {master_idx}: "
            f"got {int(pkt.id)}, expected {expected_id}"
        )
        if expected_data is not None:
            assert int(pkt.data) == expected_data, (
                f"R data mismatch at master {master_idx}: "
                f"got 0x{int(pkt.data):x}, expected 0x{expected_data:x}"
            )
        assert int(pkt.resp) == expected_resp, (
            f"R resp mismatch at master {master_idx}: "
            f"got {int(pkt.resp)}, expected {expected_resp}"
        )